#include <string>
#include <iostream>

struct Lire { std::string fichier; };
struct Ecrire { std::string contenu; };
using Commande = std::variant<Lire, Ecrire>;

void analyser(const Commande& cmd) {
    std::visit([](auto&& arg) {
        using T = std::decay_t<decltype(arg)>;
        if constexpr (std::is_same_v<T, Lire>) std::cout << "Lire " << arg.fichier;
        else if constexpr (std::is_same_v<T, Ecrire>) std::cout << "Ecrire";
    }, cmd);
}

